// InputForm.jsx — Step 2: KPIs + preferences input

import { useState } from "react";

const COLOR_SCHEMAS = [
  { id: "default", label: "Default", colors: ["#4f8ef7", "#7c5cfc", "#00d4aa", "#f7a84f"] },
  { id: "blue",    label: "Ocean",   colors: ["#0ea5e9", "#38bdf8", "#7dd3fc", "#bae6fd"] },
  { id: "warm",    label: "Warm",    colors: ["#f97316", "#fb923c", "#fbbf24", "#f43f5e"] },
  { id: "dark",    label: "Neon",    colors: ["#a78bfa", "#34d399", "#fb7185", "#fbbf24"] },
];

const QUICK_QUERIES = [
  "Revenue by category, sales by region, monthly profit trend",
  "Top 10 customers by sales, order count by ship mode",
  "Sales vs profit by sub-category, discount impact on profit",
  "Monthly sales trend, orders by segment, top products",
];

export default function InputForm({ connectionData, onSubmit, loading }) {
  const [query, setQuery] = useState("");
  const [numViz, setNumViz] = useState(4);
  const [colorSchema, setColorSchema] = useState("default");
  const [title, setTitle] = useState("My Dashboard");

  const handleSubmit = () => {
    if (!query.trim()) return;
    onSubmit({
      session_id: connectionData.session_id,
      user_query: query,
      num_visualizations: numViz,
      color_schema: colorSchema,
      dashboard_title: title,
    });
  };

  return (
    <div style={styles.wrap} className="fade-up">
      {/* Header */}
      <div style={styles.header}>
        <div style={styles.headerLeft}>
          <div style={styles.logoMini}>
            <svg width="20" height="20" viewBox="0 0 28 28" fill="none">
              <circle cx="14" cy="14" r="13" stroke="#4f8ef7" strokeWidth="1.5"/>
              <path d="M8 18 L12 10 L16 15 L20 8" stroke="#4f8ef7" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
              <circle cx="20" cy="8" r="2" fill="#7c5cfc"/>
            </svg>
          </div>
          <span style={styles.logoText}>Talking BI</span>
        </div>
        {/* DB Badge */}
        <div style={styles.dbBadge}>
          <div style={styles.dot} />
          <span>{connectionData.tables?.length} tables connected</span>
        </div>
      </div>

      <div style={styles.content}>
        {/* Left: form */}
        <div style={styles.formSide}>
          <h2 style={styles.heading}>Build your dashboard</h2>
          <p style={styles.sub}>Describe what you want to visualize in plain English</p>

          {/* Dashboard title */}
          <div style={styles.field}>
            <label style={styles.label}>Dashboard Title</label>
            <input
              style={styles.input}
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              placeholder="e.g. Sales Analytics Q4 2024"
            />
          </div>

          {/* Main query */}
          <div style={styles.field}>
            <label style={styles.label}>What do you want to see?</label>
            <textarea
              style={styles.textarea}
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="e.g. revenue by category, sales by region, monthly profit trend, top customers..."
              rows={4}
            />
          </div>

          {/* Quick queries */}
          <div style={styles.field}>
            <label style={styles.label}>Quick examples</label>
            <div style={styles.quickGrid}>
              {QUICK_QUERIES.map((q, i) => (
                <button
                  key={i}
                  style={styles.quickBtn}
                  onClick={() => setQuery(q)}
                >
                  {q}
                </button>
              ))}
            </div>
          </div>

          {/* Num visualizations */}
          <div style={styles.field}>
            <label style={styles.label}>
              Number of visualizations
              <span style={styles.numBadge}>{numViz}</span>
            </label>
            <div style={styles.numRow}>
              {[2, 3, 4, 5, 6].map((n) => (
                <button
                  key={n}
                  style={{ ...styles.numBtn, ...(numViz === n ? styles.numBtnActive : {}) }}
                  onClick={() => setNumViz(n)}
                >
                  {n}
                </button>
              ))}
            </div>
          </div>

          {/* Color schema */}
          <div style={styles.field}>
            <label style={styles.label}>Color theme</label>
            <div style={styles.colorRow}>
              {COLOR_SCHEMAS.map((s) => (
                <button
                  key={s.id}
                  style={{
                    ...styles.colorBtn,
                    ...(colorSchema === s.id ? styles.colorBtnActive : {})
                  }}
                  onClick={() => setColorSchema(s.id)}
                >
                  <div style={styles.colorSwatches}>
                    {s.colors.map((c, i) => (
                      <div key={i} style={{ ...styles.swatch, background: c }} />
                    ))}
                  </div>
                  <span>{s.label}</span>
                </button>
              ))}
            </div>
          </div>

          {/* Generate button */}
          <button
            style={{ ...styles.genBtn, ...(loading ? styles.genBtnDisabled : {}) }}
            onClick={handleSubmit}
            disabled={loading || !query.trim()}
          >
            {loading ? (
              <>
                <span style={styles.spinner} />
                Generating dashboard...
              </>
            ) : (
              <>
                <svg width="18" height="18" viewBox="0 0 18 18" fill="none">
                  <path d="M2 9h14M9 2l7 7-7 7" stroke="#fff" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
                Generate Dashboard
              </>
            )}
          </button>
        </div>

        {/* Right: schema preview */}
        <div style={styles.schemaSide}>
          <div style={styles.schemaCard}>
            <div style={styles.schemaHeader}>
              <svg width="14" height="14" viewBox="0 0 14 14" fill="none">
                <rect x="1" y="1" width="12" height="12" rx="2" stroke="#4f8ef7" strokeWidth="1.3"/>
                <path d="M1 5h12M5 5v8" stroke="#4f8ef7" strokeWidth="1.3"/>
              </svg>
              <span style={styles.schemaTitle}>Connected Schema</span>
            </div>
            <div style={styles.tableList}>
              {connectionData.tables?.map((t) => (
                <div key={t.table_name} style={styles.tableItem}>
                  <div style={styles.tableHeader}>
                    <span style={styles.tableName}>{t.table_name}</span>
                    <span style={styles.tableRows}>{t.row_count.toLocaleString()} rows</span>
                  </div>
                  <div style={styles.colList}>
                    {t.columns.slice(0, 5).map((c) => (
                      <div key={c.name} style={styles.colItem}>
                        <span style={styles.colName}>{c.name}</span>
                        <span style={styles.colType}>{c.type.split("(")[0].toLowerCase()}</span>
                      </div>
                    ))}
                    {t.columns.length > 5 && (
                      <div style={styles.moreCol}>+{t.columns.length - 5} more columns</div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

const styles = {
  wrap: { minHeight: "100vh", display: "flex", flexDirection: "column" },
  header: {
    padding: "16px 32px",
    borderBottom: "1px solid var(--border)",
    display: "flex",
    alignItems: "center",
    justifyContent: "space-between",
    background: "rgba(10,12,16,0.95)",
    backdropFilter: "blur(12px)",
    position: "sticky",
    top: 0,
    zIndex: 10,
  },
  headerLeft: { display: "flex", alignItems: "center", gap: "10px" },
  logoMini: {
    width: "36px", height: "36px",
    background: "rgba(79,142,247,0.1)",
    border: "1px solid rgba(79,142,247,0.2)",
    borderRadius: "10px",
    display: "flex", alignItems: "center", justifyContent: "center",
  },
  logoText: { fontFamily: "'Syne', sans-serif", fontWeight: 800, fontSize: "18px" },
  dbBadge: {
    display: "flex", alignItems: "center", gap: "8px",
    padding: "6px 14px",
    background: "rgba(0,212,170,0.1)",
    border: "1px solid rgba(0,212,170,0.2)",
    borderRadius: "20px",
    color: "var(--accent3)",
    fontSize: "13px",
  },
  dot: { width: "8px", height: "8px", borderRadius: "50%", background: "var(--accent3)", animation: "pulse 2s infinite" },
  content: { display: "flex", flex: 1, gap: 0 },
  formSide: { flex: 1, padding: "48px", maxWidth: "680px" },
  heading: { fontSize: "28px", fontWeight: 800, color: "#fff", marginBottom: "8px", letterSpacing: "-0.5px" },
  sub: { fontSize: "14px", color: "var(--text2)", marginBottom: "36px" },
  field: { marginBottom: "28px" },
  label: {
    display: "flex", alignItems: "center", gap: "10px",
    fontSize: "13px", fontWeight: 600, color: "var(--text2)",
    textTransform: "uppercase", letterSpacing: "0.07em", marginBottom: "10px",
  },
  numBadge: {
    background: "var(--accent)", color: "#fff",
    borderRadius: "20px", padding: "1px 8px", fontSize: "11px", fontWeight: 700,
  },
  input: {
    width: "100%", padding: "12px 16px",
    background: "var(--bg3)", border: "1px solid var(--border2)",
    borderRadius: "var(--radius)", color: "var(--text)", fontSize: "14px",
    outline: "none", fontFamily: "'DM Sans', sans-serif",
  },
  textarea: {
    width: "100%", padding: "14px 16px",
    background: "var(--bg3)", border: "1px solid var(--border2)",
    borderRadius: "var(--radius)", color: "var(--text)", fontSize: "14px",
    outline: "none", resize: "vertical", fontFamily: "'DM Sans', sans-serif",
    lineHeight: 1.6,
  },
  quickGrid: { display: "flex", flexDirection: "column", gap: "8px" },
  quickBtn: {
    padding: "10px 14px", background: "var(--bg3)", border: "1px solid var(--border)",
    borderRadius: "var(--radius)", color: "var(--text2)", fontSize: "13px",
    cursor: "pointer", textAlign: "left", transition: "all 0.15s",
  },
  numRow: { display: "flex", gap: "10px" },
  numBtn: {
    width: "48px", height: "48px",
    background: "var(--bg3)", border: "1px solid var(--border2)",
    borderRadius: "var(--radius)", color: "var(--text2)",
    fontSize: "16px", fontWeight: 600, cursor: "pointer",
    display: "flex", alignItems: "center", justifyContent: "center",
    transition: "all 0.15s",
  },
  numBtnActive: {
    background: "rgba(79,142,247,0.15)",
    border: "1px solid var(--accent)",
    color: "var(--accent)",
  },
  colorRow: { display: "flex", gap: "12px", flexWrap: "wrap" },
  colorBtn: {
    padding: "10px 16px",
    background: "var(--bg3)", border: "1px solid var(--border2)",
    borderRadius: "var(--radius)", cursor: "pointer",
    display: "flex", flexDirection: "column", alignItems: "center", gap: "8px",
    transition: "all 0.15s", color: "var(--text2)", fontSize: "12px", fontWeight: 600,
  },
  colorBtnActive: { border: "1px solid var(--accent)", background: "rgba(79,142,247,0.1)" },
  colorSwatches: { display: "flex", gap: "4px" },
  swatch: { width: "14px", height: "14px", borderRadius: "3px" },
  genBtn: {
    width: "100%", padding: "16px",
    background: "linear-gradient(135deg, var(--accent), var(--accent2))",
    border: "none", borderRadius: "var(--radius)",
    color: "#fff", fontSize: "16px", fontWeight: 700,
    fontFamily: "'Syne', sans-serif",
    cursor: "pointer", display: "flex", alignItems: "center",
    justifyContent: "center", gap: "10px", transition: "opacity 0.2s",
  },
  genBtnDisabled: { opacity: 0.5, cursor: "not-allowed" },
  spinner: {
    width: "18px", height: "18px",
    border: "2px solid rgba(255,255,255,0.3)", borderTopColor: "#fff",
    borderRadius: "50%", animation: "spin 0.7s linear infinite", display: "inline-block",
  },
  schemaSide: {
    width: "300px", borderLeft: "1px solid var(--border)",
    padding: "32px 24px", background: "var(--bg2)",
  },
  schemaCard: { position: "sticky", top: "80px" },
  schemaHeader: {
    display: "flex", alignItems: "center", gap: "8px",
    marginBottom: "20px",
  },
  schemaTitle: { fontSize: "13px", fontWeight: 600, color: "var(--text2)", textTransform: "uppercase", letterSpacing: "0.07em" },
  tableList: { display: "flex", flexDirection: "column", gap: "16px" },
  tableItem: {
    background: "var(--bg3)", border: "1px solid var(--border)",
    borderRadius: "var(--radius)", overflow: "hidden",
  },
  tableHeader: {
    display: "flex", justifyContent: "space-between", alignItems: "center",
    padding: "10px 14px", borderBottom: "1px solid var(--border)",
  },
  tableName: { fontSize: "13px", fontWeight: 700, color: "var(--accent)" },
  tableRows: { fontSize: "11px", color: "var(--text3)" },
  colList: { padding: "8px 0" },
  colItem: {
    display: "flex", justifyContent: "space-between",
    padding: "4px 14px",
  },
  colName: { fontSize: "12px", color: "var(--text2)" },
  colType: { fontSize: "11px", color: "var(--text3)", fontFamily: "monospace" },
  moreCol: { padding: "4px 14px", fontSize: "11px", color: "var(--text3)", fontStyle: "italic" },
};
